import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';

// Initialize the API client
// Note: In a production environment, this should be proxied through a backend to protect the key.
// For this portfolio demo running locally/client-side, we assume the env var is present.
const apiKey = process.env.API_KEY || ''; 
let ai: GoogleGenAI | null = null;

if (apiKey) {
  ai = new GoogleGenAI({ apiKey });
}

export const generateChatResponse = async (history: { role: string; parts: { text: string }[] }[], newMessage: string): Promise<string> => {
  if (!ai) {
    return "I'm sorry, my AI brain isn't connected right now (API Key missing). Please contact me directly via email!";
  }

  try {
    const model = 'gemini-3-flash-preview'; // Optimized for speed/chat

    // Construct the chat including system instruction
    const chat = ai.chats.create({
      model: model,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7, // Balance between creative and factual
      },
      history: history.map(h => ({
        role: h.role,
        parts: h.parts
      }))
    });

    const result = await chat.sendMessage({ message: newMessage });
    return result.text || "I didn't catch that. Could you rephrase?";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm currently experiencing high traffic. Please try asking again in a moment, or email me directly.";
  }
};

import React from 'react';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer } from 'recharts';
import { SKILLS } from '../constants';
import { Server, Cpu, Shield, Network, Terminal } from 'lucide-react';

const Skills: React.FC = () => {
  // Transform data for the radar chart
  const chartData = SKILLS.map(skill => ({
    subject: skill.category,
    A: skill.items.length * 20, // Arbitrary weight for visualization
    fullMark: 150,
  }));

  const getIcon = (category: string) => {
    if (category.includes('Data Center')) return <Server className="w-6 h-6 text-blue-400" />;
    if (category.includes('Virtualization')) return <Cpu className="w-6 h-6 text-purple-400" />;
    if (category.includes('Operating')) return <Terminal className="w-6 h-6 text-green-400" />;
    if (category.includes('Network')) return <Network className="w-6 h-6 text-orange-400" />;
    return <Shield className="w-6 h-6 text-red-400" />;
  };

  return (
    <section className="py-20 bg-slate-900" id="skills">
      <div className="container mx-auto px-4">
        <h2 className="text-3xl md:text-4xl font-bold text-center text-white mb-16">
          Technical <span className="text-blue-500">Expertise</span>
        </h2>

        <div className="flex flex-wrap items-center">
          {/* Chart Section */}
          <div className="w-full lg:w-5/12 mb-12 lg:mb-0">
            <div className="h-[400px] w-full bg-slate-800/50 rounded-2xl border border-slate-700/50 p-4 shadow-xl">
               <ResponsiveContainer width="100%" height="100%">
                <RadarChart cx="50%" cy="50%" outerRadius="70%" data={chartData}>
                  <PolarGrid stroke="#475569" />
                  <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 12 }} />
                  <PolarRadiusAxis angle={30} domain={[0, 150]} tick={false} axisLine={false} />
                  <Radar
                    name="Skill Level"
                    dataKey="A"
                    stroke="#3b82f6"
                    strokeWidth={3}
                    fill="#3b82f6"
                    fillOpacity={0.4}
                  />
                </RadarChart>
              </ResponsiveContainer>
              <p className="text-center text-slate-400 text-sm mt-4">Core Competency Distribution</p>
            </div>
          </div>

          {/* List Section */}
          <div className="w-full lg:w-7/12 lg:pl-16">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {SKILLS.map((skillGroup, index) => (
                <div key={index} className="bg-slate-800/30 p-6 rounded-xl border border-slate-700/50 hover:border-blue-500/50 transition duration-300">
                  <div className="flex items-center gap-3 mb-4">
                    {getIcon(skillGroup.category)}
                    <h3 className="text-xl font-semibold text-white">{skillGroup.category}</h3>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {skillGroup.items.map((item, i) => (
                      <span key={i} className="px-3 py-1 bg-slate-950 text-slate-300 text-sm rounded-md border border-slate-700">
                        {item}
                      </span>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Skills;

